function LSuburbMap:OnExitMap()
	if self._effectPlayer then
		self._effectPlayer:StopPlay()
	end
end

function LSuburbMap:OnPrepareEnterMap()
	local buildingInfoList  ={
		{name = "jingjichangBtn", func = function() self:JingJiChangBtn() end},
		{name = "shiliantaBtn", func = function() self:ShiLianTaBtn() end},
		{name = "chengbaoBtn", func = function() self:ChengBaoBtn() end},
		{name = "qijingBtn", func = function() self:QiJingBtn() end},
		{name = "kuafuBtn", func = function() self:KuaFuBtn() end},
		{name = "mijingBtn", func = function() self:MiJingBtn() end},
	}

	local effList = {
		--[[
		{name = "fx_chengjiao_hudie_1" , time = 3},
		{name = "fx_chengjiao_hudie_2" , time = 6},
		{name = "fx_chengjiao_hudie_3" , time = 5.5},
		{name = "fx_chengjiao_hudie_4" , time = 3.5},
		{name = "fx_chengjiao_hudie_5" , time = 9},
		{name = "fx_chengjiao_hudie_6" , time = 5},
		--]]
	}

	local chengneiEffectList = {
		--{name = "fe_chengjiao"}
	}

	local layerBuildingTrans = self._mapTrans:Find("LayerRoot/LayerBuilding")

	local len = #buildingInfoList
	for i=1,len do
		local buildingInfo = buildingInfoList[i]

		local btn = CS.FindTrans(layerBuildingTrans,buildingInfo.name)

		local func = buildingInfo.func
		if btn and func ~= nil then
			self:SetBuildClick(btn, func)
		end
	end

	local effectRootList = {}
	local chengRoot = nil

	local layerEffectTrans = CS.FindTrans(self._mapTrans,"LayerRoot/LayerEffect")
	if layerEffectTrans then
		chengRoot = CS.FindTrans(layerEffectTrans,"chengjiao")
		for i = 1,#effList do
			effectRootList[i] = CS.FindTrans(layerEffectTrans,"hudie"..i)
		end
	end

	local LMapEffectPlayer = LxRequire("LApp.Scene.Object.LMapEffectPlayer")
	if LMapEffectPlayer then
		if self._effectPlayer then
			self._effectPlayer:Destroy()
		end
		self._effectPlayer = LMapEffectPlayer:New()
		self._effectPlayer:Init(chengRoot, effectRootList, chengneiEffectList, effList)
	end
end


